# The folders in third_party are "filtered" copies of other Git repositories -
# only a single revision, with only the files we need plus files that may
# contain legal information (e.g. README and LICENSE files).
#
# Running this script will update these repositories, and stage any changes
# in Git. (Note that you should not need to do this to build the nvpro-samples
# - please create an issue instead.)
#
# Requires Python 3.11 or newer.

import argparse, datetime, glob, os, shutil, stat, subprocess, json, re
from enum import StrEnum


class Status(StrEnum):
    UP_TO_DATE = "up-to-date"
    UPDATE = "UPDATE"
    UNKNOWN = "unknown"
    ERROR = "ERROR"


def run(cmd, pipe_output: bool = False, check: bool = True) -> bytes:
    print(f"Running {cmd}", flush=True)
    stdout_hook = subprocess.PIPE if pipe_output else None
    return subprocess.run(
        cmd, shell=isinstance(cmd, str), check=check, stdout=stdout_hook
    ).stdout


# ---------------------------------------------------------------------------
# Update checking helpers
# ---------------------------------------------------------------------------
# A tag is considered "version-like" if, after stripping a leading 'v' or 'V',
# it contains at least one numeric component separated by dots. We ignore
# pre-release / build suffixes (anything after the first '-' or '+') for
# ordering purposes but keep the original string for display.
#
# Trade-off: this means tags that share the same numeric prefix compare equal,
# e.g. v1.0.0 == v1.0.0-rc1 == v1.0.0-preview. So a pre-release of a version
# we're already pinned to won't be flagged as an update, and pinning to a
# pre-release won't be flagged for update when the matching stable ships.
# This is intentional - this script is a coarse "is there something newer?"
# check, not a full semver-aware comparator. Maintainers should still review
# the upstream changelog before bumping.
_VERSION_RE = re.compile(r"^[vV]?(\d+(?:\.\d+)*)([-+].*)?$")


def parse_version(tag: str):
    """Return a tuple of ints for a version-like tag, or None if not parseable."""
    m = _VERSION_RE.match(tag.strip())
    if not m:
        return None
    try:
        return tuple(int(p) for p in m.group(1).split("."))
    except ValueError:
        return None


def ls_remote(url: str):
    """
    Run `git ls-remote <url>` and return a tuple (head_hash, heads, tags).

    - head_hash: the commit hash that HEAD on the remote points to (or None).
    - heads: dict mapping branch name -> commit hash.
    - tags: dict mapping tag name -> commit hash. Annotated tags are resolved
            to the commit they point at (via the ^{} peeled ref).
    """
    out = run(["git", "ls-remote", url], pipe_output=True).decode("utf-8", errors="replace")
    head_hash = None
    heads: dict[str, str] = {}
    tags: dict[str, str] = {}
    for line in out.splitlines():
        if "\t" not in line:
            continue
        h, ref = line.split("\t", 1)
        h = h.strip()
        ref = ref.strip()
        if ref == "HEAD":
            head_hash = h
        elif ref.startswith("refs/heads/"):
            heads[ref[len("refs/heads/"):]] = h
        elif ref.startswith("refs/tags/"):
            tag = ref[len("refs/tags/"):]
            if tag.endswith("^{}"):
                # Peeled annotated tag - overwrites the tag-object hash with
                # the commit hash, which is what we want for comparisons.
                tags[tag[:-3]] = h
            else:
                tags.setdefault(tag, h)
    return head_hash, heads, tags


def check_updates(repository: dict) -> dict:
    """
    Query the remote and figure out whether a newer version exists.

    Returns a dict with keys: name, url, current, latest, status.
        status is one of the Status enum values.
    """
    name = repository["name"]
    url = repository["url"]
    branch = repository["branch"]
    info = repository.get("info_autogenerated_from_above", {})
    current_hash = info.get("last_commit_hash", "")
    short_current = current_hash[:8] if current_hash else "?"

    def result(current: str, latest: str, status: Status) -> dict:
        return {
            "name": name,
            "url": url,
            "current": current,
            "latest": latest,
            "status": status,
        }

    try:
        head_hash, heads, tags = ls_remote(url)
    except subprocess.CalledProcessError as e:
        return result(f"{branch} ({short_current})", f"error: {e}", Status.ERROR)

    # Case 1: branch field is actually a tag.
    if branch != "None" and branch in tags:
        current_v = parse_version(branch)
        version_tags = [(parse_version(t), t) for t in tags]
        version_tags = [(v, t) for v, t in version_tags if v is not None]
        version_tags.sort()
        if version_tags and current_v is not None:
            latest_v, latest_tag = version_tags[-1]
            if latest_v > current_v:
                return result(branch, latest_tag, Status.UPDATE)
            return result(branch, latest_tag, Status.UP_TO_DATE)
        # Pinned tag with no other parseable versions: just compare commit.
        target = tags[branch]
        if not current_hash:
            return result(
                f"{branch} (?)",
                f"{branch} ({target[:8]})",
                Status.UNKNOWN,
            )
        if target != current_hash:
            return result(
                f"{branch} ({short_current})",
                f"{branch} ({target[:8]})",
                Status.UPDATE,
            )
        return result(
            f"{branch} ({short_current})",
            f"{branch} ({target[:8]})",
            Status.UP_TO_DATE,
        )

    # Case 2: branch field is a branch (or "None" -> default HEAD).
    if branch == "None":
        target = head_hash
        target_label = "HEAD"
    elif branch in heads:
        target = heads[branch]
        target_label = branch
    else:
        return result(
            f"{branch} ({short_current})",
            f"ref '{branch}' not found on remote",
            Status.UNKNOWN,
        )

    if not current_hash:
        return result(
            f"{branch} (?)",
            f"{target_label} ({target[:8]})",
            Status.UNKNOWN,
        )

    if target == current_hash:
        return result(
            f"{branch} ({short_current})",
            f"{target_label} ({target[:8]})",
            Status.UP_TO_DATE,
        )

    return result(
        f"{branch} ({short_current})",
        f"{target_label} ({target[:8]})",
        Status.UPDATE,
    )


def print_update_report(rows: list[dict]):
    """Print a simple ASCII table summarizing the update check."""
    if not rows:
        print("\nNo repositories were checked.")
        return

    headers = ("Library", "Current", "Latest", "Status", "URL")
    table = [
        (
            r["name"],
            r["current"],
            r["latest"],
            r["status"],
            r.get("url", ""),
        )
        for r in rows
    ]
    widths = [
        max(len(headers[i]), max(len(str(row[i])) for row in table))
        for i in range(len(headers))
    ]
    sep = "  "
    line = sep.join(h.ljust(w) for h, w in zip(headers, widths, strict=True))
    rule = sep.join("-" * w for w in widths)
    print()
    print("Third-party update report")
    print("=" * len(line))
    print(line)
    print(rule)
    for row in table:
        print(sep.join(str(c).ljust(w) for c, w in zip(row, widths, strict=True)))
    print()
    n_update = sum(1 for r in rows if r["status"] == Status.UPDATE)
    n_uptodate = sum(1 for r in rows if r["status"] == Status.UP_TO_DATE)
    n_unknown = sum(1 for r in rows if r["status"] == Status.UNKNOWN)
    n_error = sum(1 for r in rows if r["status"] == Status.ERROR)
    print(
        f"Summary: {n_update} update(s) available, {n_uptodate} up-to-date, "
        f"{n_unknown} unknown, {n_error} error(s)."
    )


def on_error_enable_write_access_and_retry(func, path, excinfo):
    # Does the path exist, at least?
    if os.path.exists(path):
        # Try making it writable
        os.chmod(path, stat.S_IWUSR | os.stat(path).st_mode)
        func(path)
    else:
        raise


def rm_recursive_if_exists(path: str):
    print(f"Removing {path}")
    if os.path.exists(path):
        if os.path.isdir(path):
            shutil.rmtree(path, onerror=on_error_enable_write_access_and_retry)
        else:
            os.remove(path)


def rebuild(repository: dict):
    """
    Removes and recreates a single third_party "filtered repository".

    Parameters
    ----------
    repository : dict
        A dictionary containing information about a repository. This function
        can read the following fields:
            "name": The folder name in third_party to place the repository's files.

            "url": https:// or ssh:// URL for the upstream .git repository.

            "branch" (str, optional): If specified, downloads a specific branch
            of the repository. For instance, this can be used to pin a
            dependency to a specific version or feature branch. The default is
            None.

            "remove_globs" (list[str], optional): Each element is a glob
            specification; files matching any specification will be removed.
            The default is [].

        This function adds the following fields to repository_data:
            "last_updated_utc": UTC time when the repository was pulled.

            "last_commit_hash": Commit hash pulled.

            "last_commit_time": ISO 8601 time (with time zone) of the last
            commit made.

    Raises
    ------
    RuntimeError
        If the folder to clone to isn't a third_party directory.

    Returns
    -------
    None.

    """
    script_dir = os.path.dirname(os.path.abspath(__file__))
    clone_folder_absolute = os.path.abspath(
        os.path.join(script_dir, repository["name"])
    )
    # Some quick checks to make sure we don't remove the root directory
    if "third_party" not in clone_folder_absolute:
        raise RuntimeError(
            f"script_dir {script_dir} didn't seem to be the third_party directory."
        )
    try:
        run(["git", "rm", "-r", "-f", clone_folder_absolute])
    except Exception as e:
        print(f"git rm failed with code {e}")
    # Also delete any left-over files that Git doesn't track
    rm_recursive_if_exists(clone_folder_absolute)
    # Clone the repository there.
    # Surprisingly, this works even if nvpro_core itself is a Git repo!
    clone_args = [
        "git",
        "clone",
        "--depth",
        "1",
        "--recurse-submodules",
        "--single-branch",
    ]
    branch = repository["branch"]
    if branch != "None":
        clone_args += ["--branch", branch]
    clone_args += ["--", repository["url"], clone_folder_absolute]
    run(clone_args)
    # Get information about the cloned Git repo
    autogen_info = {}
    autogen_info["last_updated_utc"] = datetime.datetime.now(
        tz=datetime.timezone.utc
    ).isoformat()
    autogen_info["last_commit_hash"] = (
        run(["git", "-C", clone_folder_absolute, "rev-parse", "HEAD"], pipe_output=True)
        .decode("utf-8")
        .strip()
    )
    autogen_info["last_commit_time"] = (
        run(
            [
                "git",
                "-C",
                clone_folder_absolute,
                "log",
                "-1",
                "--date=iso-strict",
                "--format=%ad",
            ],
            pipe_output=True,
        )
        .decode("utf-8")
        .strip()
    )
    repository["info_autogenerated_from_above"] = autogen_info
    # Always remove the git history, plus some standard file names.
    remove_globs = [
        ".git",
        ".gitattributes",
        ".github",
        "**/.gitignore",
        ".travis.yml",
        ".circleci",
        ".clang-format",
        "appveyor.yml",
        "**/*.sln",
        "**/*.vcxproj",
        "**/*.vcxproj.filters",
        "**/*.sh",
        "**/*.com",
        "**/*.bat",
        "**/*.manifest",
        "**/Makefile",
        "**/MAKEFILE",
        "**/*.mk",
        "**/*.pdf",
    ] + repository["rules"]
    # Iterate over filters and remove any found files.
    for globspec in remove_globs:
        paths = glob.glob(globspec, root_dir=clone_folder_absolute, recursive=True)
        for path in paths:
            rm_recursive_if_exists(os.path.join(clone_folder_absolute, path))
    # Sometimes nvpro_core ignores files from subrepos. But adding `-f` is not
    # the best solution, because if we do that, it'll trip up the bulk-update
    # script later.
    # Instead, if you run into this, fix nvpro_core's .gitignore. (You can add
    # ! at the start of lines to make .gitignore not apply to certain directories.)
    run(["git", "add", clone_folder_absolute])


if __name__ == "__main__":
    parser = argparse.ArgumentParser(
        prog="dev-rebuild-filtered-repos",
        description='The folders in third_party are "filtered" copies of other Git repositories; this script updates them.',
    )
    parser.add_argument(
        "repositories",
        nargs="*",
        default=[],
        help="Names of repositories from repro_rules.json to update. You can specify multiple repositories like this: `dev-rebuild-filtered-repos.py imgui fmt stb`. By default, updates every repository.",
    )
    parser.add_argument(
        "--check-updates",
        action="store_true",
        help="Don't rebuild anything; just query each remote and print an ASCII "
        "report of which third-party libraries have new tags or commits "
        "available compared to the version recorded in repro_rules.json.",
    )
    args = parser.parse_args()

    script_dir = os.path.dirname(os.path.abspath(__file__))
    rules_path = os.path.join(script_dir, "repro_rules.json")

    # Load the JSON file with repository rules
    with open(rules_path, "r") as json_file:
        data = json.load(json_file)

    selected = data["repositories"]
    if args.repositories:
        selected = [r for r in selected if r["name"] in args.repositories]

    if args.check_updates:
        report_rows = []
        for repository in selected:
            report_rows.append(check_updates(repository))
        print_update_report(report_rows)
    else:
        for repository in selected:
            rebuild(repository)
        # Save updated data
        with open(rules_path, "w") as json_file:
            json_file.write(json.dumps(data, indent=4))
        # And now that we've saved that, add the file to git:
        run(["git", "add", rules_path])
